// The strategy begins with unconstrained generation to ensure a free-text output.
// Once the delimiter " << " is encountered, it switches to a constrained step
// to generate a valid expression within the delimited region. The strategy
// ensures that the generated expression remains valid throughout the process.
// The delimiter " >> " is used to mark the end of the constrained region.
// The strategy terminates when the maximum number of steps is reached or when
// the parser determines that the current prefix is complete.
// CSD_RATIONALE_END

generated := [];
stepsLeft := maxSteps;

var leftDelimiterPos := 0; // Track the position of the left delimiter

while stepsLeft > 0 && !parser.IsCompletePrefix(generated) {
    var next: Token;
    var newSteps: nat;

    if (leftDelimiterPos == 0 && parser.IsValidPrefix(generated) && !parser.IsCompletePrefix(generated)) {
        // Unconstrained step: generate a token until the left delimiter is found
        next, newSteps := helpers.UnconstrainedStep(prompt, generated, stepsLeft);
    } else if (leftDelimiterPos > 0 && helpers.InsideDelimitedWindow(generated) && !parser.IsCompletePrefix(helpers.GetDelimitedContent(generated))) {
        // Constrained step: generate a token within the delimited region
        next, newSteps := helpers.ConstrainedStep(prompt, generated, stepsLeft);
    } else {
        // Unconstrained step: generate a token regardless of the current state
        next, newSteps := helpers.UnconstrainedStep(prompt, generated, stepsLeft);
    }

    generated := generated + [next];
    stepsLeft := newSteps;

    // Update the position of the left delimiter if it's found
    if (next == LeftDelimiter) {
        leftDelimiterPos := |generated| - 1;
    }
}

